private static void ReverseThemeWithAnimation()
{
    var condition = ThemeManager.Current == typeof(Dark);
    if (condition)
    {
        // Appliquer une transition vers le thème clair avec animation
        ThemeManager.Transition<Light>(TransitionEffects.Theme);
    }
    else
    {
        // Appliquer une transition vers le thème sombre avec animation
        ThemeManager.Transition<Dark>(TransitionEffects.Theme);
    }
}

private static void ReverseThemeWithOutAnimation()
{
    // Condition pour vérifier si le thème actuel est sombre
    var condition = ThemeManager.Current == typeof(Dark);
    if (condition)
    {
        // Basculer vers le thème clair sans animation
        ThemeManager.Jump<Light>();
    }
    else
    {
        // Basculer vers le thème sombre sans animation
        ThemeManager.Jump<Dark>();
    }
}

